import React from 'react';
import { Link } from 'react-router-dom';
import './Home.css';

const Home = () => {
  return (
    <div className="home-container">
      <div className="hero-section">
        <h1>Find the Best <span>Freelance</span> Talent</h1>
        <p>तुमच्या प्रोजेक्टसाठी कुशल फ्रीलान्सर्स शोधा किंवा काम करून पैसे कमवा.</p>
        <div className="hero-btns">
          <Link to="/marketplace" className="btn-primary">Explore Jobs</Link>
          <Link to="/signup" className="btn-secondary">Join Now</Link>
        </div>
      </div>
    </div>
  );
};

export default Home;
